import{_ as t,a}from"./chunks/listcontexmenu.BPReYXTv.js";import{_ as o,o as i,c as r,ae as n}from"./chunks/framework.C00B0EYs.js";const y=JSON.parse('{"title":"List Editor","description":"Edit traction and brake keyframes in a table-based view.","frontmatter":{"title":"List Editor","description":"Edit traction and brake keyframes in a table-based view."},"headers":[],"relativePath":"docs/guide/list-editor.md","filePath":"docs/guide/list-editor.md"}'),s={name:"docs/guide/list-editor.md"};function l(d,e,c,h,u,m){return i(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="list-editor" tabindex="-1">List Editor <a class="header-anchor" href="#list-editor" aria-label="Permalink to &quot;List Editor&quot;">​</a></h1><p>The chart editor is the main creation surface, but it is not the only one. Motor Sound Editor also provides <strong>List Editor</strong>, a table-based way to work with keyframe data.</p><p>When you need to review, correct, or enter many keyframes precisely, the list editor offers more direct numeric feedback than the chart view.</p><p><img src="'+t+'" alt="List view"></p><h2 id="_1-core-purpose" tabindex="-1">1. Core purpose <a class="header-anchor" href="#_1-core-purpose" aria-label="Permalink to &quot;1. Core purpose&quot;">​</a></h2><p>The list editor maps the current track&#39;s keyframes into a table so you can manage them more like spreadsheet data.</p><ul><li><strong>Precise input</strong>: you can type exact values such as <code>60.5 km/h</code> or <code>0.85</code>.</li><li><strong>Global overview</strong>: you can review a whole track&#39;s keyframe distribution in one place and catch jumps or redundant points more easily.</li><li><strong>Side-by-side editing</strong>: the current implementation shows both <strong>Traction</strong> and <strong>Brake</strong> data at the same time, with separate Pitch and Volume columns.</li></ul><h2 id="_2-layout" tabindex="-1">2. Layout <a class="header-anchor" href="#_2-layout" aria-label="Permalink to &quot;2. Layout&quot;">​</a></h2><p>The table is organized into these main areas:</p><ol><li>a <strong>Traction</strong> section with speed and value columns</li><li>a <strong>Brake</strong> section with speed and value columns</li><li>separate <strong>Pitch</strong> and <strong>Volume</strong> columns inside each section</li></ol><h2 id="_3-draft-editing-model" tabindex="-1">3. Draft editing model <a class="header-anchor" href="#_3-draft-editing-model" aria-label="Permalink to &quot;3. Draft editing model&quot;">​</a></h2><p>The list editor uses a draft-based flow:</p><ul><li>edits stay inside the dialog while you work</li><li><strong>Apply</strong> writes the draft back to the project</li><li><strong>Cancel</strong> discards the current draft</li></ul><h2 id="_4-automatic-sorting" tabindex="-1">4. Automatic sorting <a class="header-anchor" href="#_4-automatic-sorting" aria-label="Permalink to &quot;4. Automatic sorting&quot;">​</a></h2><p>Keyframes are always sorted by speed. If you change the speed of a keyframe, the visible row order may change automatically so the table remains logically ordered.</p><h2 id="_5-right-click-context-menu" tabindex="-1">5. Right-click context menu <a class="header-anchor" href="#_5-right-click-context-menu" aria-label="Permalink to &quot;5. Right-click context menu&quot;">​</a></h2><p>You can open a context menu by right clicking either in the chart area or inside the list editor.</p><p><img src="'+a+'" alt="Right-click context menu"></p><p>Common list-editor actions currently include:</p><ul><li><strong>Sync traction to brake / Sync brake to traction</strong> to copy one side&#39;s data to the other</li><li><strong>Add keyframe</strong> to insert a new point and let it join the sorted list automatically</li><li><strong>Delete current keyframe</strong> to remove the selected point</li></ul>',20)])])}const f=o(s,[["render",l]]);export{y as __pageData,f as default};
